j=A.c(["\u0422\u0440\u0438\u0430\u043b 7 \u0434\u043d\u0435\u0439 \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u0435\u0442 \u0432\u0441\u0451 \u2014 \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u0443\u0441\u043f\u0435\u0432\u0430\u0435\u0442 \u043f\u0440\u043e\u0436\u0438\u0442\u044c \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u0443\u044e \u043f\u0435\u0442\u043b\u044e.","\u0413\u043e\u0434\u043e\u0432\u043e\u0439 \u0442\u0430\u0440\u0438\u0444 \u043f\u0440\u043e\u0434\u0430\u0451\u0442\u0441\u044f \u043a\u0430\u043a \xab\u0432\u0435\u0441\u044c \u043c\u0430\u0440\u0448\u0440\u0443\u0442 \u0433\u043e\u0434\u0430\xbb, \u043c\u0435\u0441\u044f\u0447\u043d\u044b\u0439 \u2014 \u0440\u044f\u0434\u043e\u043c \u0434\u043b\u044f \u043a\u043e\u043d\u0442\u0440\u0430\u0441\u0442\u0430.","\u0411\u0435\u0441\u043f\u043b\u0430\u0442\u043d\u044b\u0439 \u0441\u043b\u043e\u0439 \u043e\u0441\u0442\u0430\u0451\u0442\u0441\u044f \u0438 \u043f\u043e\u0441\u043b\u0435 \u043e\u0442\u043a\u0430\u0437\u0430: \u043f\u043e\u0433\u043e\u0434\u0430 \u0434\u043d\u044f, \u043a\u0430\u0440\u0442\u0430, 1 \u0432\u043e\u043f\u0440\u043e\u0441 \u041a\u043e\u043c\u043f\u0430\u0441\u0443 \u2014 \u043c\u0430\u0433\u043d\u0438\u0442 \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u0434\u0430\u043b\u044c\u0448\u0435."],k)
o=A.c(["\u0413\u043e\u0434\u043e\u0432\u0430\u044f \u043f\u043e\u0434\u043f\u0438\u0441\u043a\u0430 \u0434\u0435\u0440\u0436\u0438\u0442 \u043f\u043e\u0434\u043f\u0438\u0441\u0447\u0438\u043a\u043e\u0432 \u043a\u0440\u0430\u0442\u043d\u043e \u043b\u0443\u0447\u0448\u0435 \u043c\u0435\u0441\u044f\u0447\u043d\u043e\u0439 (\u043f\u043e \u0431\u0435\u043d\u0447\u043c\u0430\u0440\u043a\u0430\u043c ~36% \u043f\u0440\u043e\u0442\u0438\u0432 ~7% \u0447\u0435\u0440\u0435\u0437 \u0433\u043e\u0434) \u2014 \u044d\u0442\u043e \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u0430\u044f \u0431\u0430\u0437\u0430 rev-share.","\u041f\u0435\u0440\u0432\u044b\u0435 \u0432\u043e\u043b\u043d\u044b \u043f\u0440\u0438\u0434\u0443\u0442 \u043f\u0440\u043e\u0433\u0440\u0435\u0442\u044b\u043c\u0438 \u0438\u0437 \u0432\u0430\u0448\u0438\u0445 \u0441\u043e\u0446\u0441\u0435\u0442\u0435\u0439 \u2014 \u043c\u043d\u043e\u0433\u0438\u0435 \u0441 \u0443\u0436\u0435 \u043e\u043f\u043b\u0430\u0447\u0435\u043d\u043d\u044b\u043c\u0438 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u0430\u043c\u0438: \u0434\u043b\u044f \u043d\u0438\u0445 \u043f\u0435\u0439\u0432\u043e\u043b\u043b \u043c\u043e\u0436\u0435\u0442 \u0431\u044b\u0442\u044c \u0443\u0436\u0435 \xab\u043e\u0442\u043a\u0440\u044b\u0442\xbb."],k)
o=A.qH(A.c(["\u0426\u0435\u043d\u044b \u2014 \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440 \u0434\u043b\u044f \u043e\u0431\u0441\u0443\u0436\u0434\u0435\u043d\u0438\u044f (\u0433\u043e\u0434 7 990 \u20bd \u2248 \u043a\u043b\u0443\u0431\u0443 \xab\u0421\u043c\u044b\u0441\u043b\u044b\xbb). \u041a\u0430\u043a\u0430\u044f \u043b\u043e\u0433\u0438\u043a\u0430 \u0446\u0435\u043d \u0440\u044f\u0434\u043e\u043c \u0441 \u043a\u043b\u0443\u0431\u043e\u043c?","\u0421\u043e\u0441\u0442\u0430\u0432 \u0431\u0435\u0441\u043f\u043b\u0430\u0442\u043d\u043e\u0433\u043e \u0441\u043b\u043e\u044f: \u0447\u0442\u043e \u043e\u0441\u0442\u0430\u0432\u0438\u0442\u044c \u043e\u0442\u043a\u0440\u044b\u0442\u044b\u043c \u043d\u0430\u0432\u0441\u0435\u0433\u0434\u0430?","\u0410\u043b\u044c\u0442\u0435\u0440\u043d\u0430\u0442\u0438\u0432\u0430 \u043d\u0430 \u043f\u043e\u0442\u043e\u043c: \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u044f\u044f \u0432\u0430\u043b\u044e\u0442\u0430 (\xab\u043a\u0440\u0438\u0441\u0442\u0430\u043b\u043b\u044b\xbb) \u0437\u0430 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0438 \u0438 \u043f\u0440\u0438\u0433\u043b\u0430\u0448\u0435\u043d\u0438\u044f \u2014 \u0434\u043b\u044f \u0434\u0435\u043c\u043e \u0441\u043e\u0437\u043d\u0430\u0442\u0435\u043b\u044c\u043d\u043e \u043d\u0435 \u0443\u0441\u043b\u043e\u0436\u043d\u044f\u043b\u0438.","\u041a\u0430\u043a \u0432\u043f\u0443\u0441\u043a\u0430\u0442\u044c \u0442\u0435\u0445, \u043a\u0442\u043e \u0443\u0436\u0435 \u043e\u043f\u043b\u0430\u0442\u0438\u043b \u0432\u0430\u0448\u0438 \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u044b?"],k),B.et,j,B.c1,"\u041f\u0435\u0439\u0432\u043e\u043b\u043b","\u041f\u0435\u0439\u0432\u043e\u043b\u043b: \u043c\u0430\u0440\u0448\u0440\u0443\u0442 \u0433\u043e\u0434\u0430","\u042d\u043a\u0440\u0430\u043d \u043f\u043e\u0434\u043f\u0438\u0441\u043a\u0438 \u0441\u0440\u0430\u0437\u0443 \u043f\u043e\u0441\u043b\u0435 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438: 7 \u0434\u043d\u0435\u0439 \u0431\u0435\u0441\u043f\u043b\u0430\u0442\u043d\u043e, \u0443\u043f\u043e\u0440 \u043d\u0430 \u0433\u043e\u0434\u043e\u0432\u043e\u0439 \u0442\u0430\u0440\u0438\u0444.",o)
j=A.c(["\u0428\u0430\u043f\u043a\u0430 \u043e\u0442\u0432\u0435\u0447\u0430\u0435\u0442 \u043d\u0430 \xab\u0433\u0434\u0435 \u044f\xbb: \u0433\u043b\u0430\u0432\u0430 \u0433\u043e\u0434\u0430 \u2192 \u0442\u0435\u043c\u0430 \u043c\u0435\u0441\u044f\u0446\u0430 \u2192 \u0434\u0435\u043d\u044c 6 \u0438\u0437 21 \u2192 \u043f\u043e\u0433\u043e\u0434\u0430 \u0434\u043d\u044f.","\u041d\u0438\u0436\u0435 \u2014 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u044b \u0434\u043d\u044f: \u043a\u0430\u0440\u0442\u0430 (\u043f\u0435\u0440\u0435\u0432\u0435\u0440\u043d\u0438\u0442\u0435 \u0435\u0451!), \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0430 \u043d\u0430 5 \u043c\u0438\u043d\u0443\u0442, \u0441\u0435\u0440\u0438\u044f \u0434\u043d\u0435\u0439, \u0432\u0445\u043e\u0434 \u043a \u041a\u043e\u043c\u043f\u0430\u0441\u0443.","\u0423\u0442\u0440\u0435\u043d\u043d\u0438\u0439 \u043f\u0443\u0448 \xab\u041f\u043e\u0433\u043e\u0434\u0430 \u0434\u043d\u044f\xbb \u0437\u0430\u043c\u044b\u043a\u0430\u0435\u0442 \u043f\u0435\u0442\u043b\u044e: \u043f\u0443\u0448 \u2192 \u044d\u043a\u0440\u0430\u043d \u2192 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0430 \u2192 \u0434\u043d\u0435\u0432\u043d\u0438\u043a \u2192 \u0441\u0435\u0440\u0438\u044f."],k)
n=A.c(["\u041f\u043e\u0433\u043e\u0434\u0430 \u0434\u043d\u044f \u2014 \u043f\u0440\u0438\u0447\u0438\u043d\u0430 \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u0442\u044c \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u043e; \u0441\u0435\u0440\u0438\u044f \u0434\u043d\u0435\u0439 \u0438 \xab\u0448\u0430\u0433 6 \u0438\u0437 21\xbb \u0434\u0435\u043b\u0430\u044e\u0442 \u043f\u0430\u0443\u0437\u0443 \u0434\u043e\u0440\u043e\u0433\u043e\u0439.","\u041e\u0442 \u0432\u0430\u0441 \u2014 \u0440\u0430\u0437 \u0432 \u043c\u0435\u0441\u044f\u0446: \u043f\u043e\u0433\u043e\u0434\u0430 \u043c\u0435\u0441\u044f\u0446\u0430 + \u043d\u0430\u0431\u043e\u0440 \u043f\u0440\u0430\u043a\u0442\u0438\u043a. \u0414\u0430\u043b\u044c\u0448\u0435 \u043f\u0435\u0442\u043b\u044f \u043a\u0440\u0443\u0442\u0438\u0442\u0441\u044f \u0441\u0430\u043c\u0430, \u0431\u0435\u0437 \u043a\u043e\u043c\u0430\u043d\u0434\u044b."],k)
